  color: #fff;
}

.button-light {
  background: #fff;
  color: #222;
}
```

--------------------------------

### Using Context as a Provider

Source: https://github.com/reactjs/react.dev/blob/main/src/content/blog/2024/12/05/react-19.md

In React 19, you can render the Context object directly as a provider instead of using <Context.Provider>.

```javascript
const ThemeContext = createContext('');

function App({children}) {
  return (
    <ThemeContext value="dark">
      {children}
    </ThemeContext>
  );
}
```

--------------------------------

### Manage localStorage using useLocalStorage custom hook in React JSX

Source: https://context7.com/reactjs/react.dev/llms.txt

This hook provides a way to persist state in the browser's localStorage. It initializes state from storage if available and provides a setter that updates both the React state and the local storage value.

```jsx
import { useState, useCallback } from 'react';

function useLocalStorage(key, initialValue) {
  const [storedValue, setStoredValue] = useState(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = useCallback((value) => {
    setStoredValue(value);
    window.localStorage.setItem(key, JSON.stringify(value));
  }, [key]);

  return [storedValue, setValue];
}
```

--------------------------------

### Synchronize Video Player with React State using useEffect

Source: https://github.com/reactjs/react.dev/blob/main/src/content/learn/escape-hatches.md

Use this pattern to control imperative browser APIs like a video player based on React props. The dependency array ensures the Effect re-runs only when the tracked value changes.

```js
import { useState, useRef, useEffect } from 'react';

function VideoPlayer({ src, isPlaying }) {
  const ref = useRef(null);

  useEffect(() => {
    if (isPlaying) {
      ref.current.play();
    } else {
      ref.current.pause();
    }
  }, [isPlaying]);

  return <video ref={ref} src={src} loop playsInline />;
}

export default function App() {
  const [isPlaying, setIsPlaying] = useState(false);
  return (
    <>
      <button onClick={() => setIsPlaying(!isPlaying)}>
        {isPlaying ? 'Pause' : 'Play'}
      </button>
      <VideoPlayer
        isPlaying={isPlaying}
        src="https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4"
      />
    </>
  );
}
```

```css
button { display: block; margin-bottom: 20px; }
video { width: 250px; }
```

--------------------------------

### Complete Example: Context with `use` and Conditional Styling

Source: https://github.com/reactjs/react.dev/blob/main/src/content/reference/react/use.md

A full application demonstrating context creation, provision, and consumption using the `use` Hook, including conditional rendering and styling.

```js
import { createContext, use } from 'react';

const ThemeContext = createContext(null);

export default function MyApp() {
  return (
    <ThemeContext value="dark">
      <Form />
    </ThemeContext>
  )
}

function Form() {
  return (
    <Panel title="Welcome">
      <Button show={true}>Sign up</Button>
      <Button show={false}>Log in</Button>
    </Panel>
  );
}

function Panel({ title, children }) {
  const theme = use(ThemeContext);
  const className = 'panel-' + theme;
  return (
    <section className={className}>
      <h1>{title}</h1>
      {children}
    </section>
  )
}

function Button({ show, children }) {
  if (show) {
    const theme = use(ThemeContext);
    const className = 'button-' + theme;
    return (
      <button className={className}>
        {children}
      </button>
    );
  }
  return false
}
```

