1	import { useEffect, useMemo, useState } from 'react'
2	import { LayoutGroup } from 'motion/react'
3	import * as api from './api/client'
4	import type { TodoList, TodoListItem } from './api/types'
5	import Header from './components/Header'
6	import ListsBoard from './components/ListsBoard'
7	import ActiveListPanel from './components/ActiveListPanel'
8	import UndoToast from './components/UndoToast'
9	import { useUndoToast } from './hooks/useUndoToast'
10	import './App.css'
11	
12	function App() {
13	  const [lists, setLists] = useState<TodoList[]>([])
14	  const [itemsByList, setItemsByList] = useState<Record<number, TodoListItem[]>>({})
15	  const [selectedId, setSelectedId] = useState<number | null>(null)
16	  const [autoFocusListId, setAutoFocusListId] = useState<number | null>(null)
17	  const [loading, setLoading] = useState(true)
18	  const [bootError, setBootError] = useState<string | null>(null)
19	  const undo = useUndoToast()
20	
21	  useEffect(() => {
22	    let cancelled = false
23	    async function bootstrap() {
24	      try {
25	        const fetched = await api.getLists()
26	        if (cancelled) return
27	        const itemEntries = await Promise.all(
28	          fetched.map(async (list) => [list.id, await api.getItems(list.id)] as const),
29	        )
30	        if (cancelled) return
31	        const map: Record<number, TodoListItem[]> = {}
32	        for (const [id, items] of itemEntries) map[id] = items
33	        setLists(fetched)
34	        setItemsByList(map)
35	        setSelectedId(fetched[0]?.id ?? null)
36	      } catch (e) {
37	        if (!cancelled) setBootError((e as Error).message)
38	      } finally {
39	        if (!cancelled) setLoading(false)
40	      }
41	    }
42	    bootstrap()
43	    return () => {
44	      cancelled = true
45	    }
46	  }, [])
47	
48	  async function handleAddList(name: string) {
49	    const created = await api.createList(name)
50	    setLists((prev) => [...prev, created])
51	    setItemsByList((prev) => ({ ...prev, [created.id]: [] }))
52	    setSelectedId(created.id)
53	    setAutoFocusListId(created.id)
54	  }
55	
56	  async function handleRenameList(id: number, name: string) {
57	    const previousName = lists.find((l) => l.id === id)?.name
58	    setLists((prev) => prev.map((l) => (l.id === id ? { ...l, name } : l)))
59	    try {
60	      const updated = await api.updateList(id, name)
61	      setLists((prev) => prev.map((l) => (l.id === id ? { ...l, name: updated.name } : l)))
62	    } catch (e) {
63	      if (previousName !== undefined) {
64	        setLists((prev) =>
65	          prev.map((l) => (l.id === id ? { ...l, name: previousName } : l)),
66	        )
67	      }
68	      throw e
69	    }
70	  }
71	
72	  function requestDeleteList(id: number) {
73	    const target = lists.find((l) => l.id === id)
74	    if (!target) return
75	    const targetItems = itemsByList[id] ?? []
76	    const remaining = lists.filter((l) => l.id !== id)
77	    const nextSelected =
78	      id === selectedId ? remaining[0]?.id ?? null : selectedId
79	
80	    // optimistic remove
81	    setLists(remaining)
82	    setItemsByList((prev) => {
83	      const next = { ...prev }
84	      delete next[id]
85	      return next
86	    })
87	    if (id === selectedId) setSelectedId(nextSelected)
88	
89	    undo.schedule({
90	      label: `Deleted “${target.name}”`,
91	      commit: async () => {
92	        try {
93	          await api.deleteList(id)
94	        } catch {
95	          // restore on failure
96	          setLists((prev) => [...prev, target].sort((a, b) => a.id - b.id))
97	          setItemsByList((prev) => ({ ...prev, [id]: targetItems }))
98	        }
99	      },
100	      undo: () => {
101	        setLists((prev) => [...prev, target].sort((a, b) => a.id - b.id))
102	        setItemsByList((prev) => ({ ...prev, [id]: targetItems }))
103	        setSelectedId(target.id)
104	      },
105	    })
106	  }
107	
108	  async function handleAddItem(listId: number, description: string) {
109	    const tempId = -Date.now()
110	    const optimistic: TodoListItem = {
111	      id: tempId,
112	      description,
113	      isCompleted: false,
114	      todoListId: listId,
115	    }
116	    setItemsByList((prev) => ({
117	      ...prev,
118	      [listId]: [...(prev[listId] ?? []), optimistic],
119	    }))
120	    try {
121	      const created = await api.createItem(listId, description)
122	      setItemsByList((prev) => ({
123	        ...prev,
124	        [listId]: (prev[listId] ?? []).map((i) => (i.id === tempId ? created : i)),
125	      }))
126	    } catch (e) {
127	      setItemsByList((prev) => ({
128	        ...prev,
129	        [listId]: (prev[listId] ?? []).filter((i) => i.id !== tempId),
130	      }))
131	      throw e
132	    }
133	  }
134	
135	  async function handleToggleItem(listId: number, item: TodoListItem) {
136	    const nextCompleted = !item.isCompleted
137	    setItemsByList((prev) => ({
138	      ...prev,
139	      [listId]: (prev[listId] ?? []).map((i) =>
140	        i.id === item.id ? { ...i, isCompleted: nextCompleted } : i,
141	      ),
142	    }))
143	    try {
144	      const updated = await api.updateItem(listId, item.id, {
145	        description: item.description,
146	        isCompleted: nextCompleted,
147	      })
148	      setItemsByList((prev) => ({
149	        ...prev,
150	        [listId]: (prev[listId] ?? []).map((i) => (i.id === updated.id ? updated : i)),
151	      }))
152	    } catch (e) {
153	      setItemsByList((prev) => ({
154	        ...prev,
155	        [listId]: (prev[listId] ?? []).map((i) =>
156	          i.id === item.id ? { ...i, isCompleted: item.isCompleted } : i,
157	        ),
158	      }))
159	      throw e
160	    }
