1	import { useState, type FormEvent, type KeyboardEvent } from 'react'
2	import { motion } from 'motion/react'
3	
4	interface Props {
5	  onAdd: (name: string) => Promise<void> | void
6	  disabled?: boolean
7	}
8	
9	function AddListForm({ onAdd, disabled }: Props) {
10	  const [value, setValue] = useState('')
11	  const [submitting, setSubmitting] = useState(false)
12	  const [active, setActive] = useState(false)
13	
14	  async function commit() {
15	    const trimmed = value.trim()
16	    if (!trimmed || submitting) return
17	    setSubmitting(true)
18	    try {
19	      await onAdd(trimmed)
20	      setValue('')
21	      setActive(false)
22	    } finally {
23	      setSubmitting(false)
24	    }
25	  }
26	
27	  async function handleSubmit(e: FormEvent) {
28	    e.preventDefault()
29	    await commit()
30	  }
31	
32	  function handleKey(e: KeyboardEvent<HTMLInputElement>) {
33	    if (e.key === 'Escape') {
34	      setValue('')
35	      setActive(false)
36	      ;(e.currentTarget as HTMLInputElement).blur()
37	    }
38	  }
39	
40	  return (
41	    <motion.form
42	      className={`add-list-card${active ? ' is-active' : ''}`}
43	      onSubmit={handleSubmit}
44	      whileHover={{ y: -2 }}
45	      transition={{ type: 'spring', stiffness: 320, damping: 28 }}
46	      aria-label="Create a new list"
47	    >
48	      <span className="add-list-card-plus" aria-hidden>
49	        +
50	      </span>
51	      <input
52	        type="text"
53	        placeholder="new list"
54	        value={value}
55	        onChange={(e) => setValue(e.target.value)}
56	        onFocus={() => setActive(true)}
57	        onBlur={() => {
58	          if (!value.trim()) setActive(false)
59	        }}
60	        onKeyDown={handleKey}
61	        disabled={disabled || submitting}
62	        aria-label="New list name"
63	      />
64	      <button
65	        type="submit"
66	        className="add-list-card-submit"
67	        disabled={disabled || submitting || !value.trim()}
68	        aria-label="Create list"
69	      >
70	        ↵
71	      </button>
72	    </motion.form>
73	  )
74	}
