interface Props {
  list: TodoList
  items: TodoListItem[]
  onAddItem: (description: string) => Promise<void> | void
  onToggleItem: (item: TodoListItem) => Promise<void> | void
  onDeleteItem: (item: TodoListItem) => void
  onRenameList: (name: string) => Promise<void> | void
  onDeleteList: () => void
  autoFocusInput?: boolean
  onAutoFocusConsumed?: () => void
}

function ActiveListPanel({
  list,
  items,
  onAddItem,
  onToggleItem,
  onDeleteItem,
  onRenameList,
  onDeleteList,
  autoFocusInput,
  onAutoFocusConsumed,
}: Props) {
  const pastel = getPastelForList(list.id)
  const total = items.length
  const done = items.filter((i) => i.isCompleted).length

  const [editing, setEditing] = useState(false)
  const [draftName, setDraftName] = useState(list.name)
  const [error, setError] = useState<string | null>(null)
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    setDraftName(list.name)
    setError(null)
  }, [list.id, list.name])

  useEffect(() => {
    if (editing) inputRef.current?.select()
  }, [editing])

  function startEdit() {
    setDraftName(list.name)
    setEditing(true)
  }

  async function commitEdit() {
    if (!editing) return
    const trimmed = draftName.trim()
    setEditing(false)
    if (!trimmed || trimmed === list.name) return
    try {
      await onRenameList(trimmed)
    } catch (e) {
      setError((e as Error).message)
    }
  }

  function cancelEdit() {
    setEditing(false)
    setDraftName(list.name)
  }

  function handleKey(e: KeyboardEvent<HTMLInputElement>) {
    if (e.key === 'Enter') {
      e.preventDefault()
      void commitEdit()
    } else if (e.key === 'Escape') {
      e.preventDefault()
      cancelEdit()
    }
  }

