          fetched.map(async (list) => [list.id, await api.getItems(list.id)] as const),
        )
        if (cancelled) return
        const map: Record<number, TodoListItem[]> = {}
        for (const [id, items] of itemEntries) map[id] = items
        setLists(fetched)
        setItemsByList(map)
        setSelectedId(fetched[0]?.id ?? null)
